"""
# Definition for a Node.
class Node:
    def __init__(self, val: int = 0, left: 'Node' = None, right: 'Node' = None, next: 'Node' = None):
        self.val = val
        self.left = left
        self.right = right
        self.next = next
"""

class Solution:
    def connect(self, root: 'Node') -> 'Node':

        temp_head = root
        while temp_head:
            temp = Node()
            tail = temp

            while temp_head:
                if temp_head.left:
                    tail.next = temp_head.left
                    tail = tail.next
                if temp_head.right:
                    tail.next = temp_head.right
                    tail = tail.next
                temp_head = temp_head.next


            temp_head = temp.next

        return root
